SELECT view_count
FROM channel_analytics
WHERE channel_id = 1;

SELECT MAX(last_updated) AS most_recent_update
FROM service_analytics
WHERE service_id = 0;

SELECT SUM(view_count) AS total_views
FROM channel_analytics
WHERE channel_id = 1;

SELECT service_name
FROM streaming_services
WHERE trial_period IS NOT NULL;

SELECT channel_id, average_rating
FROM channel_analytics
ORDER BY average_rating DESC;

SELECT channel_id
FROM channel_analytics
WHERE engagement_score = (SELECT MAX(engagement_score) FROM channel_analytics);

SELECT average_view_time
FROM service_analytics
WHERE service_id = 1;

SELECT COUNT(channel_id) AS channel_count
FROM channel_availability
WHERE service_id = 1;
